import { Readable } from 'stream';

async function processStream(stream: Readable): Promise<void> {
  for await (const chunk of stream) {
    process.stdout.write(chunk.toString()); // Print each chunk as it arrives
  }
  console.log('\n[Stream complete]');
}

import OpenAI from 'openai';

const client = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

async function streamCompletion(): Promise<void> {
  const stream = await client.chat.completions.create({
    model: 'gpt-4o',
    messages: [{ role: 'user', content: 'Explain Node.js in one paragraph' }],
    stream: true,
  });

  for await (const chunk of stream) {
    const delta = chunk.choices[0]?.delta?.content ?? '';
    process.stdout.write(delta);
  }

  console.log('\nDone.');
}

